{"type":"doc","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Принцип "},{"type":"text","marks":[{"type":"bold"}],"text":"“transparent reactivity”"},{"type":"text","text":" (прозрачная реактивность) — один из ключевых идеологических принципов библиотеки "},{"type":"text","marks":[{"type":"bold"}],"text":"Zustand"},{"type":"text","text":", который объясняет, "},{"type":"text","marks":[{"type":"italic"}],"text":"почему она кажется «магически» реактивной без лишнего кода"},{"type":"text","text":"."}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"🧠 Простое определение"}]},{"type":"blockquote","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"Transparent reactivity"},{"type":"text","text":" означает, что компоненты React автоматически обновляются, когда изменяются те части состояния, к которым они “подписаны” — без дополнительного кода, провайдеров или ручных подписок."}]}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Иными словами, "},{"type":"text","marks":[{"type":"bold"}],"text":"реактивность “прозрачна”"},{"type":"text","text":":"},{"type":"hardBreak"},{"type":"text","text":"ты просто читаешь данные из стора в компоненте, а Zustand "},{"type":"text","marks":[{"type":"bold"}],"text":"сам"},{"type":"text","text":" следит за их изменениями и вызывает ререндер, когда нужно."}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"🔍 Пример"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"import { create } from 'zustand'

const useStore = create(() => ({
  count: 0,
  inc: () => set((s) => ({ count: s.count + 1 })),
}))

function Counter() {
  const count = useStore((s) => s.count) // ← просто читаем count
  const inc = useStore((s) => s.inc)

  return (
