      <button onClick={inc}>+</button>
    </div>
  )
}
"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Ты нигде явно не подписываешься на обновления, не вызываешь "},{"type":"text","marks":[{"type":"code"}],"text":"subscribe()"},{"type":"text","text":", не передаёшь контекст —"},{"type":"hardBreak"},{"type":"text","text":"а React "},{"type":"text","marks":[{"type":"bold"}],"text":"сам перерисовывает"},{"type":"text","text":" "},{"type":"text","marks":[{"type":"code"}],"text":"Counter"},{"type":"text","text":", когда "},{"type":"text","marks":[{"type":"code"}],"text":"count"},{"type":"text","text":" изменился."},{"type":"hardBreak"},{"type":"text","text":"Это и есть "},{"type":"text","marks":[{"type":"italic"}],"text":"transparent reactivity"},{"type":"text","text":"."}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"⚙️ Как это работает “под капотом”"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Zustand использует "},{"type":"text","marks":[{"type":"bold"}],"text":"механизм подписок (subscription system)"},{"type":"text","text":", который:"}]},{"type":"orderedList","attrs":{"start":1,"type":null},"content":[{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"хранит текущее состояние в одном объекте (store);"}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"позволяет каждому компоненту вызывать "},{"type":"text","marks":[{"type":"code"}],"text":"useStore(selector)"},{"type":"text","text":";"}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"подписывает компонент на "},{"type":"text","marks":[{"type":"italic"}],"text":"результат селектора"},{"type":"text","text":";"}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"при изменении состояния сравнивает старое и новое значение;"}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"если они отличаются — вызывает ререндер компонента."}]}]}]},{"type":"blockquote","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Компонент не знает ничего о механизме подписок — он просто “работает” → реактивность “прозрачна”."}]}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"🔄 Сравнение с другими подходами"}]},{"type":"table","content":[{"type":"tableRow","content":[{"type":"tableHeader","attrs":{"colspan":1,"rowspan":1,"colwidth":null},"content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Подход"}]}]},{"type":"tableHeader","attrs":{"colspan":1,"rowspan":1,"colwidth":null},"content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Реактивность"}]}]},{"type":"tableHeader","attrs":{"colspan":1,"rowspan":1,"colwidth":null},"content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Прозрачность"}]}]}]},{"type":"tableRow","content":[{"type":"tableCell","attrs":{"colspan":1,"rowspan":1,"colwidth":null},"content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"Redux (классический)"}]}]},{"type":"tableCell","attrs":{"colspan":1,"rowspan":1,"colwidth":null},"content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"через "},{"type":"text","marks":[{"type":"code"}],"text":"connect()"},{"type":"text","text":" или "},{"type":"text","marks":[{"type":"code"}],"text":"useSelector()"}]}]},{"type":"tableCell","attrs":{"colspan":1,"rowspan":1,"colwidth":null},"content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"частично (нужно оборачивать)"}]}]}]},{"type":"tableRow","content"